s"><ul><li class="nav__item--footer"><a class="item__footer--link" href="/en/footer/imprint"><span class="item__footer--text">Imprint</span></a></li><li class="nav__item--footer"><a class="item__footer--link" href="/en/footer/privacy-statement"><span class="item__footer--text">Privacy statement</span></a></li><li class="nav__item--footer"><a class="item__footer--link" href="/en/footer/legal-notice"><span class="item__footer--text">Legal notice</span></a></li><li class="nav__item--footer"><a class="item__footer--link" href="javascript: UC_UI.showSecondLayer();"><span class="item__footer--text">Cookie settings</span></a></li></ul></div></div></div><div class="footer__content footer__centerContent col-lg-4"><div class="neos-contentcollection">
         <div class="content__text">
           <h3>Support Our Work</h3>
           <p>If you wish to make a donation or support our projects, please contact us directly using our inquiry form.</p>
