a7-6f9f80875aa0'',''name'':''SwissContact_Sud-Ouest_DSC_3577_HD.jpg'',''title'':'''',''alt'':'''',''hash'':''7c7ea4f574a7bba9cc7f827b95899900cc85d0a0'',''maxwidth'':''5568'',''originalwidth'':''5568'',''originalheight'':''2758''}" style="padding-bottom: 49.533045977011%"></div></div></div><div class="nav__breadcrumb"><ol><li class="nav__breadcrumb--item"><a class="breadcrumb--link" href="/en"><span class="nav__breadcrumb--text">Home</span></a><span class="nav__breadcrumb--divider"></span></li><li class="nav__breadcrumb--item"><a class="breadcrumb--link" href="/en/where-we-work"><span class="nav__breadcrumb--text">Where we work</span></a><span class="nav__breadcrumb--divider"></span></li><li class="nav__breadcrumb--item lastItem"><span class="nav__breadcrumb--text">Burkina Faso</span><span class="nav__breadcrumb--divider"></span></li></ol></div><div class="lead__content sideContent container"><div class="row"><div class="sideContent--left col-12 col-lg-6 col-xl-7"><div class="main__content--headline"><h1>Burkina Faso</h1></div><div class="ce__lead"><div class="ce__lead--content"><div class="ce__lead--text">Burkina Faso</span><span>&nbsp;is a&nbsp;</span><span>landlocked country</span><span>&nbsp;in&nbsp;</span><span>West Africa</span><span>. In recent years, the government has made education in general, and youth entrepreneurship and vocational training in particular, a budgetary priority, efforts bolstered by an unprecedented influx of aid to the sector. The economic growth rate is high; Burkina Faso has a wealth of natural resources and there is a growing food processing industry and a nascent tech sector. Other bright spots include high rates of social media use amongst youth, growing mobile and internet phone penetration, and an active culture of youth associations. Above all, the energy and dynamism of the youth themselves present a significant source of untapped potential for future growth.</div></div></div></div><div class="country__sideContent col-12 col-lg-5 offset-lg-1 col-xl-4"><div class="sideContent--box"><div class="sideContent--map"><div class="img-ari--responsive" data-ari-respectheight="true" data-ari-params="{''id'':''0b4cb341-ba84-4e3f-a68e-d8c86fc829a1'',''name'':''burkina-faso.png'',''title'':'''',''alt'':'''',''hash'':''8ba4ea51331c7ff344b57a65cf283d38ce6999a2'',''maxwidth'':''664'',''originalwidth'':''664'',''originalheight'':''504''}"></div></div><div class="sideContent--headline">BURKINA FASO</div><div class="sideContent--infos"><h3><strong>Figures</strong></h3><ul><li>Area: 267.950 km2</li><li>Population: 19.7 million</li><li>Capital:&nbsp;Ouagadougou</li></ul><h3><strong>Swisscontact in BURKINA FASO</strong></h3><ul><li>since 1998</li></ul></div></div></div></div></div><main class="main__content"><div class="backgroundContainer"><div class="container"><div class="teaserGroup teaserGroup__2col" data-internezz-teaser--teasergroup><div class="row"><div class="teaserGroup__headline col-12"><h3>Projects</h3></div><div class="teaserGroup__link col-12"><a href="/en/projects?country=bf" title="View all projects from Burkina Faso">View all projects from Burkina Faso</a></div><div class="teaser__element teaser__2col col-12 col-lg-6 " data-internezzo-teaser--uniqueTeasedNodeIdentifier="3ea56be5-f642-45a3-b21f-f2622c74db57"><div class="teaser__image teaser__image--2col"><div class="img-ari--responsive" data-ari-params="{''id'':''f1109634-9176-46f5-9db5-d38be67720b9'',''name'':''_DSC4685.jpg'',''title'':'''',''alt'':'''',''hash'':''b34e1c1e74b1a40f64596a3a36494a6df54417a7'',''maxwidth'':''5472'',''originalwidth'':''5472'',''originalheight'':''3646''}" style="padding-bottom: 66.630116959064%"></div></div><div class="teaser__element--wrapper"><div class="teaser__box"><div class="teaser__box--tagGroup"><div class="teaser__tagGroup"><div class="teaser__tagGroup--tag tags-duration"><span>2020 - 2025</span></div></div><div class="teaser__tagGroup"><div class="teaser__tagGroup--tag tags-country"><span>Niger, Burkina Faso</span></div></div><div class="teaser__tagGroup"><div class="teaser__tagGroup--tag tags-workingArea"><span>Initial vocational education and training, Labour market insertion</span></div></div></div><div class="teaser__box--title">Bridge Youth Connect</div><div class="teaser__box--text">The purpose of YC is to facilitate access to strategic economic and social opportunities for vulnerable youth in Niger and Burkina Faso.&nbsp;</div></div><a href="/en/projects/bridge-youth-connect" class="teaser--link" title></a></div></div></div></div></div></div><div class="container"><div class="teaserGroup teaserGroup__2col" data-internezz-teaser--teasergroup><div class="row"><div class="teaserGroup__headline col-12"><h3>News</h3></div><div class="teaserGroup__link col-12"><a href="/en/news?country=bf" title="View all news from Burkina Faso">View all news from Burkina Faso</a></div><div class="teaser__element teaser__2col col-12 col-lg-6 teaser--news" data-internezzo-teaser--uniqueTeasedNodeIdentifier="23de798d-f404-40ea-8963-40acba226c76"><div class="teaser__image teaser__image--2col"><div class="img-ari--responsive" data-ari-params="{''id'':''2779cc97-74c5-42b7-b078-aff740b7f3df'',''name'':''_MG_7957.jpg'',''title'':'''',''alt'':'''',''hash'':''99fa204710f6a9a1981d1e5a3d735b14308cf7d0'',''maxwidth'':''5049'',''originalwidth'':''5049'',''originalheight'':''3368''}" style="padding-bottom: 66.706278470984%"></div></div><div class="teaser__element--wrapper"><div class="teaser__box"><div class="teaser__box--tagGroup"><div class="teaser__tagGroup"><div class="teaser__tagGroup--tag tags-country"><span>Mali, Niger, Chad, Burkina Faso</span></div></div><div class="teaser__tagGroup"><div class="teaser__tagGroup--tag tags-workingArea"><span>Initial vocational education and training</span></div></div></div><div class="teaser__box--date">13.11.2024</div><div class="teaser__box--title">Sustainable Development in Fragile Contexts: A Complex Quest</div><div class="teaser__box--text">In the 21st century, humanity is pursuing an ambitious mission: to make our world more equitable, sustainable, and prosperous for everyone. This vision, encapsulated in the United Nations’ Sustainable Development Goals (SDGs), unites nations, international organizations, and NGOs in the effort to improve living conditions, reduce inequalities, and promote social cohesion. However, while the SDGs offer a hopeful roadmap, achieving them in fragile contexts - regions plagued by political instability, conflict, natural disasters, and poverty - is an especially formidable challenge.</div></div><a href="/en/news/sustainable-development-in-fragile-contexts-a-complex-quest-1" class="teaser--link" title></a></div></div></div></div></div><div class="container"><div class="multicolumn__twoCol"><div class="row twoCol--4and8"><div class="2col--right col-12 col-lg-8"><div class="content__facts"><div class="facts--headline"><h3>OUR APPROACH</h3></div><div class="facts--text"><p>Opportunities for the vast majority of young people are limited. An underdeveloped private sector offers few options, the portfolio of work activities influenced by the seasonal agricultural calendar and migration. Agriculture dominates the economy, but training in the agro-sylvo-pastoral field is under-resourced, and despite its potential, the majority of young people do not perceive agriculture as a rewarding option.</p><p>Swisscontact is developing market-friendly and contextual vocational training that meets local developmental needs and ensures participation and inclusion of local stakeholders.&nbsp;</p><p>Swisscontact contributes to the improvement of the living conditions of rural youth, by the establishment of training-systems and the integration of trained youths into the labour market.</p><p><strong>Therefore we support</strong>&nbsp;young people to achieve their potential through technical and soft-skills training, improved access to career coaching, business development support and financial services. We focus on&nbsp;<strong>agricultural, technical and soft skills development,&nbsp;</strong>including support via existing government platforms. Additional activities include the promotion of value chains to take advantage of business opportunities to increase incomes and create jobs. Additionally, we facilitate access to Financial Services.&nbsp;</p></div></div></div></div></div></div><div class="neos-contentcollection"><div class="container content__button"><div class="d-print-none btn"><p class="btn--linked"><a href="https://www.swisscontact.online/fr/pays/burkina-faso">Additional news and content on the&nbsp;french version of this page</span><span>&nbsp;</a></p></div></div><div class="container content__assetlist"><div class="row justify-content-md-center"><div class="col-12 col-md-10 col-lg-8"><div class="assetlist__title"><h2>Swisscontact in Burkina Faso</h2></div><div class="assetlist__list"><div class="asset__element"><a target="_blank" class="asset__element--link" href="https://www.swisscontact.online/_Resources/Persistent/2/1/b/8/21b884f7287d4fd519c6f53ea0ccb2f8fcfef3ad/Histoire%20Burkina%20Faso%20en-US.pdf" title="History of Swisscontact in Burkina Faso"><div class="asset__element--title asset--file">History of Swisscontact in Burkina Faso</div></a><div class="asset__element--infos"><span class="asset__element--size">417 kB</span></div></div></div></div></div></div></div><div class="container" data-nezzo-usercentrics-consentplaceholder="{&quot;serviceName&quot;:&quot;amCharts&quot;,&quot;placeholderFor&quot;:&quot;Internezzo.Country:AmChartsLoader&quot;,&quot;autoReplaceOnConsent&quot;:true,&quot;replaceWith&quot;:&quot;&quot;,&quot;data&quot;:[]}"><div class="consentplaceholder-text"><h3>We need your consent to load this content.</h3><p>We use the service of a third-party provider to offer this content. Please check the details and accept the service to activate this plug-in.</p></div><div data-nezzo-usercentrics-cmptrigger="1" class="d-print-none btn consen